def _set_process_priority(self, pid: int) -> None:
    if self.process_priority is None:
        return

    try:
        if WIN:
            import ctypes

            priority_classes = {
                "low": 0x00000040,  # IDLE_PRIORITY_CLASS
                "below_normal": 0x00004000,  # BELOW_NORMAL_PRIORITY_CLASS
                "normal": 0x00000020,  # NORMAL_PRIORITY_CLASS
                "above_normal": 0x00008000,  # ABOVE_NORMAL_PRIORITY_CLASS
                "high": 0x00000080,  # HIGH_PRIORITY_CLASS
            }
            handle = ctypes.windll.kernel32.OpenProcess(  # type: ignore[attr-defined]
                0x0200 | 0x0400, False, pid  # PROCESS_SET_INFORMATION | PROCESS_QUERY_INFORMATION
            )
            if handle:
                try:
                    ctypes.windll.kernel32.SetPriorityClass(  # type: ignore[attr-defined]
                        handle, priority_classes[self.process_priority]
                    )
                finally:
                    ctypes.windll.kernel32.CloseHandle(handle)  # type: ignore[attr-defined]
        else:
            niceness = {
                "low": 10,
                "below_normal": 5,
                "normal": 0,
                "above_normal": -5,
                "high": -10,
            }
            os.setpriority(os.PRIO_PROCESS, pid, niceness[self.process_priority])
    except (OSError, AttributeError, KeyError, ValueError):
        # Setting the priority is best-effort; if it's not supported
        # on this platform or fails for any reason, ignore it and
        # let the editor continue running with the default priority.
        pass

